using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 25m, Quantity = 1 },
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45m, order.Total);
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10m, Quantity = 1 },
        };

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    [TestMethod]
    public void CreateOrder_AssignsUniqueIdAndTimestamp()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5m, Quantity = 1 },
        };

        var before = DateTime.UtcNow;
        var order = _sut.CreateOrder("cust-1", items);
        var after = DateTime.UtcNow;

        Assert.IsNotNull(order.Id);
        Assert.IsInRange(order.CreatedAt, before, after);
    }

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsOrder()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10m, Quantity = 1 },
        };
        var created = _sut.CreateOrder("cust-1", items);

        var retrieved = _sut.GetOrder(created.Id);

        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("non-existent");

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10m, Quantity = 1 },
        };
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-2", items);

        var results = _sut.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, results);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var results = _sut.GetOrdersByCustomer("unknown");

        Assert.IsEmpty(results);
    }
}
```

**Key practices used:**
- **`sealed` test class** — better performance, signals no inheritance
- **`Assert.ThrowsExactly<T>`** — matches only the exact exception type
- **Constructor for init** — enables `readonly` fields
- **Specific assertions** — `HasCount`, `IsEmpty`, `AreSame`, `IsInRange` over generic `IsTrue`
- **AAA pattern** with `MethodName_Scenario_ExpectedBehavior` naming
